business_data = locals()['var_function-call-15160251058364179117']

category_reviews = {}

for business in business_data:
    description = business.get('description', '')
    review_count = int(business.get('review_count', '0'))

    # Extract categories from description. Assuming categories are listed after 'in the fields of' or 'offers a range of services in' or 'offers a delightful selection of treats, making it a must-visit for anyone seeking'
    # or 'offers a delightful array of dishes in the category of'
    categories_str = ''
    if 'in the fields of' in description:
        categories_str = description.split('in the fields of')[1].split('.')[0]
    elif 'offers a range of services in' in description:
        categories_str = description.split('offers a range of services in')[1].split('.')[0]
    elif 'making it a must-visit for anyone seeking' in description:
        categories_str = description.split('making it a must-visit for anyone seeking')[1].split('.')[0]
    elif 'offers a delightful array of dishes in the category of' in description:
        categories_str = description.split('offers a delightful array of dishes in the category of')[1].split('.')[0]

    if categories_str:
        categories = [cat.strip() for cat in categories_str.split(',')]
        for category in categories:
            if category:
                category_reviews[category] = category_reviews.get(category, 0) + review_count

sorted_categories = sorted(category_reviews.items(), key=lambda item: item[1], reverse=True)
top_5_categories = sorted_categories[:5]

print('__RESULT__:')
print(json.dumps(top_5_categories))"}

